resource "aws_iam_role" "synthetic_role_149" {
  name = "synthetic_role_149"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_149_policy" {
  name   = "synthetic_role_149-policy"
  role   = aws_iam_role.synthetic_role_149.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "*"
            ],
            "Resource": "arn:aws:s3:::*",
            "Condition": {
                "IpAddress": {
                    "aws:SourceIp": [
                        "10.0.0.0/8"
                    ]
                }
            }
        }
    ]
})
}
